static inline uint8_t knn_predict_pelvic_rotation(const float features[KNN_FEATURE_COUNT])
{
    float x[KNN_FEATURE_COUNT];
    float best_dist[KNN_K];
    uint8_t best_label[KNN_K];

    for (int i = 0; i < KNN_FEATURE_COUNT; i++) {
        x[i] = (features[i] - KNN_MEAN[i]) / KNN_SCALE[i];
    }

    for (int i = 0; i < KNN_K; i++) {
        best_dist[i] = FLT_MAX;
        best_label[i] = KNN_STATIC_SITTING;
    }

    for (int ref = 0; ref < KNN_REFERENCE_COUNT; ref++) {
        float d2 = 0.0f;
        for (int i = 0; i < KNN_FEATURE_COUNT; i++) {
            float diff = x[i] - KNN_REFERENCE[ref][i];
            d2 += diff * diff;
        }

        int worst = 0;
        for (int i = 1; i < KNN_K; i++) {
            if (best_dist[i] > best_dist[worst]) {
                worst = i;
            }
        }
        if (d2 < best_dist[worst]) {
            best_dist[worst] = d2;
            best_label[worst] = KNN_LABEL[ref];
        }
    }

    float static_vote = 0.0f;
    float rotation_vote = 0.0f;
    for (int i = 0; i < KNN_K; i++) {
        float weight = 1.0f / (sqrtf(best_dist[i]) + 1.0e-6f);
        if (best_label[i] == KNN_PELVIC_ROTATION) {
            rotation_vote += weight;
        } else {
            static_vote += weight;
        }
    }

    return (rotation_vote > static_vote) ? KNN_PELVIC_ROTATION : KNN_STATIC_SITTING;
}

